(function(){
var body = document.body;
var btn = document.querySelector('.menu-btn');
var overlay = document.querySelector('.menu-overlay');
var drawer = document.querySelector('.menu-drawer');
function open(){ body.classList.add('menu-open'); btn.setAttribute('aria-expanded','true'); drawer.setAttribute('aria-hidden','false'); overlay.setAttribute('aria-hidden','false'); }
function close(){ body.classList.remove('menu-open'); btn.setAttribute('aria-expanded','false'); drawer.setAttribute('aria-hidden','true'); overlay.setAttribute('aria-hidden','true'); }
btn.addEventListener('click', function(){ body.classList.contains('menu-open') ? close() : open(); });
overlay.addEventListener('click', close);
document.querySelectorAll('.menu-drawer a').forEach(function(a){ a.addEventListener('click', close); });
document.addEventListener('keydown', function(e){ if(e.key === 'Escape') close(); });
})();